+import type { AnyColumn } from '~/column.ts';
+import { sql, type SQL, type SQLWrapper } from '../sql.ts';
+
+/** A boundary of a window frame. */
+export type WindowFrameBoundary =
+	| typeof unboundedPreceding
+	| typeof currentRow
+	| typeof unboundedFollowing
+	| { readonly type: 'preceding' | 'following'; readonly value: number };
+
+export interface WindowFrameSpec {
+	readonly type: 'rows' | 'range';
+	readonly from: WindowFrameBoundary;
+	readonly to: WindowFrameBoundary;
+}
+
+export interface WindowSpec {
+	partitionBy?: SQLWrapper | SQLWrapper[];
+	orderBy?: SQLWrapper | SQLWrapper[];
+	frame?: WindowFrameSpec;
+}
+
+export const unboundedPreceding = { type: 'unbounded preceding' } as const;
+export const currentRow = { type: 'current row' } as const;
+export const unboundedFollowing = { type: 'unbounded following' } as const;
+
+function assertFrameOffset(name: 'preceding' | 'following', value: number): void {
+	if (!Number.isInteger(value) || value < 0) {
+		throw new Error(`${name}() requires a non-negative integer, received ${value}`);
+	}
+}
+
+export function preceding(value: number): WindowFrameBoundary {
+	assertFrameOffset('preceding', value);
+	return { type: 'preceding', value };
+}
+
+export function following(value: number): WindowFrameBoundary {
+	assertFrameOffset('following', value);
+	return { type: 'following', value };
+}
+
+function boundaryPosition(boundary: WindowFrameBoundary): number {
+	if (boundary === unboundedPreceding) return Number.NEGATIVE_INFINITY;
+	if (boundary === currentRow) return 0;
+	if (boundary === unboundedFollowing) return Number.POSITIVE_INFINITY;
+	return boundary.type === 'preceding' ? -boundary.value : boundary.value;
+}
+
+function frame(type: WindowFrameSpec['type'], spec: { from: WindowFrameBoundary; to: WindowFrameBoundary }): WindowFrameSpec {
+	if (boundaryPosition(spec.from) > boundaryPosition(spec.to)) {
+		throw new Error('Window frame "from" boundary must not be ordered after "to" boundary');
+	}
+	return { type, ...spec };
+}
+
+export function rows(spec: { from: WindowFrameBoundary; to: WindowFrameBoundary }): WindowFrameSpec {
+	return frame('rows', spec);
+}
+
+export function range(spec: { from: WindowFrameBoundary; to: WindowFrameBoundary }): WindowFrameSpec {
+	return frame('range', spec);
+}
+
+function boundarySql(boundary: WindowFrameBoundary): SQL {
+	if (boundary === unboundedPreceding) return sql.raw('unbounded preceding');
+	if (boundary === currentRow) return sql.raw('current row');
+	if (boundary === unboundedFollowing) return sql.raw('unbounded following');
+	return sql`${sql.raw(String(boundary.value))} ${sql.raw(boundary.type)}`;
+}
+
+function overSql(spec: WindowSpec | string): SQL {
+	if (typeof spec === 'string') return sql` over ${sql.identifier(spec)}`;
+	const partitionBy = spec.partitionBy ? (Array.isArray(spec.partitionBy) ? spec.partitionBy : [spec.partitionBy]) : [];
+	const orderBy = spec.orderBy ? (Array.isArray(spec.orderBy) ? spec.orderBy : [spec.orderBy]) : [];
+	const partitionSql = partitionBy.length ? sql` partition by ${sql.join(partitionBy, sql`, `)}` : undefined;
+	const orderSql = orderBy.length ? sql` order by ${sql.join(orderBy, sql`, `)}` : undefined;
+	const frameSql = spec.frame
+		? sql` ${sql.raw(spec.frame.type)} between ${boundarySql(spec.frame.from)} and ${boundarySql(spec.frame.to)}`
+		: undefined;
+	return sql` over (${partitionSql}${orderSql}${frameSql})`;
+}
+
+export class WindowFunction<T> implements SQLWrapper {
+	constructor(private readonly expression: SQL<T>) {}
+	over(spec: WindowSpec | string = {}): SQL<T> {
+		return sql`${this.expression}${overSql(spec)}`;
+	}
+	getSQL(): SQL<T> {
+		return this.expression;
+	}
+}
+
+type ValueOf<T extends SQLWrapper> = T extends AnyColumn ? T['_']['data'] : T extends SQL<infer TValue> ? TValue : unknown;
+type Expression = SQLWrapper | unknown;
+function expression(value: Expression): SQL {
+	return value && typeof value === 'object' && 'getSQL' in value ? sql`${value as SQLWrapper}` : sql`${value}`;
+}
+function positional(name: string, value: number | undefined): SQL | undefined {
+	return value === undefined ? undefined : sql`${sql.raw(String(value))}`;
+}
+function positiveInteger(name: string, value: number): void {
+	if (!Number.isInteger(value) || value <= 0) throw new Error(`${name}() requires a positive integer, received ${value}`);
+}
+function valueFunction<T extends SQLWrapper>(name: string, value: T, position?: number, defaultValue?: Expression): WindowFunction<ValueOf<T> | null> {
+	const args = [expression(value), positional(name, position), defaultValue === undefined ? undefined : expression(defaultValue)].filter((arg): arg is SQL => arg !== undefined);
+	return new WindowFunction(sql`${sql.raw(name)}(${sql.join(args, sql`, `)})`);
+}
+
+export function rowNumber(): WindowFunction<number> { return new WindowFunction(sql`row_number()`); }
+export function rank(): WindowFunction<number> { return new WindowFunction(sql`rank()`); }
+export function denseRank(): WindowFunction<number> { return new WindowFunction(sql`dense_rank()`); }
+export function ntile(buckets: number): WindowFunction<number> { positiveInteger('ntile', buckets); return new WindowFunction(sql`ntile(${sql.raw(String(buckets))})`); }
+export function percentRank(): WindowFunction<number> { return new WindowFunction(sql`percent_rank()`); }
+export function cumeDist(): WindowFunction<number> { return new WindowFunction(sql`cume_dist()`); }
+export function lag<T extends SQLWrapper>(value: T, offset?: number): WindowFunction<ValueOf<T> | null>;
+export function lag<T extends SQLWrapper, TDefault>(value: T, offset: number | undefined, defaultValue: TDefault): WindowFunction<Exclude<ValueOf<T>, null>>;
+export function lag<T extends SQLWrapper>(value: T, offset?: number, defaultValue?: Expression): WindowFunction<ValueOf<T> | null> { return valueFunction('lag', value, offset, defaultValue); }
+export function lead<T extends SQLWrapper>(value: T, offset?: number): WindowFunction<ValueOf<T> | null>;
+export function lead<T extends SQLWrapper, TDefault>(value: T, offset: number | undefined, defaultValue: TDefault): WindowFunction<Exclude<ValueOf<T>, null>>;
+export function lead<T extends SQLWrapper>(value: T, offset?: number, defaultValue?: Expression): WindowFunction<ValueOf<T> | null> { return valueFunction('lead', value, offset, defaultValue); }
+export function firstValue<T extends SQLWrapper>(value: T): WindowFunction<ValueOf<T> | null> { return valueFunction('first_value', value); }
+export function lastValue<T extends SQLWrapper>(value: T): WindowFunction<ValueOf<T> | null> { return valueFunction('last_value', value); }
+export function nthValue<T extends SQLWrapper>(value: T, nth: number): WindowFunction<ValueOf<T> | null> { positiveInteger('nthValue', nth); return valueFunction('nth_value', value, nth); }
+export function windowSum(value: SQLWrapper): WindowFunction<string | null> { return new WindowFunction(sql`sum(${value})`); }
+export function windowAvg(value: SQLWrapper): WindowFunction<string | null> { return new WindowFunction(sql`avg(${value})`); }
+export function windowMin<T extends SQLWrapper>(value: T): WindowFunction<ValueOf<T> | null> { return new WindowFunction(sql`min(${value})`); }
+export function windowMax<T extends SQLWrapper>(value: T): WindowFunction<ValueOf<T> | null> { return new WindowFunction(sql`max(${value})`); }
+export function windowCount(value?: SQLWrapper): WindowFunction<number> { return new WindowFunction(sql`count(${value ?? sql.raw('*')})`); }
