+import { PgDialect, pgTable, serial } from '~/pg-core';
+import { PgSelectBuilder } from '~/pg-core/query-builders/select.ts';
+import {
+	currentRow,
+	following,
+	lag,
+	ntile,
+	preceding,
+	range,
+	rowNumber,
+	rows,
+	windowCount,
+	windowSum,
+} from '~/sql/functions/window.ts';
+
+const users = pgTable('users', { id: serial('id') });
+const dialect = new PgDialect();
+
+function query(sql: { getSQL(): ReturnType<typeof rowNumber>['getSQL'] }) {
+	return dialect.sqlToQuery(sql.getSQL()).sql;
+}
+
+test('window helpers render positional arguments literally and compile frames', () => {
+	expect(query(rowNumber().over({}))).toBe('row_number() over ()');
+	expect(query(lag(users.id, 0).over({ orderBy: users.id }))).toBe('lag("users"."id", 0) over (order by "users"."id")');
+	expect(query(ntile(4).over({ partitionBy: users.id }))).toBe('ntile(4) over (partition by "users"."id")');
+	expect(query(windowSum(users.id).over({ frame: rows({ from: preceding(2), to: currentRow }) }))).toBe('sum("users"."id") over (rows between 2 preceding and current row)');
+	expect(query(windowCount().over({ frame: range({ from: currentRow, to: following(1) }) }))).toBe('count(*) over (range between current row and 1 following)');
+});
+
+test('named windows render before order by and use quoted references', () => {
+	const select = new PgSelectBuilder({ fields: { rank: rowNumber().over('rank_window') }, dialect, session: undefined })
+		.from(users)
+		.window('rank_window', { orderBy: users.id })
+		.orderBy(users.id);
+	expect(dialect.sqlToQuery(select.getSQL()).sql).toBe('select row_number() over "rank_window" from "users" window "rank_window" as (order by "users"."id") order by "users"."id"');
+});
+
+test('window validation rejects invalid values', () => {
+	expect(() => ntile(0)).toThrow('ntile');
+	expect(() => preceding(-1)).toThrow('preceding');
+	expect(() => rows({ from: following(1), to: currentRow })).toThrow('from');
+});
